from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest
import time
import threading

app = Flask(__name__)

# Metrics
REQUEST_COUNT = Counter('flask_requests_total', 'Total HTTP requests', ['method', 'endpoint', 'status'])
REQUEST_LATENCY = Histogram('flask_request_duration_seconds', 'HTTP request latency')
ACTIVE_REQUESTS = Gauge('flask_active_requests', 'Number of active requests')
BUSINESS_METRIC = Counter('business_operations_total', 'Total business operations')

# Middleware to track requests
@app.before_request
def start_timer():
    request.start_time = time.time()

@app.after_request
def record_metrics(response):
    duration = time.time() - request.start_time
    REQUEST_COUNT.labels(method=request.method, endpoint=request.endpoint or 'unknown', status=response.status_code).inc()
    REQUEST_LATENCY.observe(duration)
    return response

@app.route('/metrics')
def metrics():
    return generate_latest()

@app.route('/health')
def health():
    return jsonify({'status': 'healthy'}), 200

@app.route('/business/<operation>')
def business_operation(operation):
    BUSINESS_METRIC.inc()
    # Simulate some work
    time.sleep(0.1)
    return jsonify({'operation': operation, 'status': 'completed'})

@app.route('/slow')
def slow_endpoint():
    time.sleep(2)
    return jsonify({'message': 'Slow operation completed'})

@app.route('/error')
def error_endpoint():
    return jsonify({'error': 'Something went wrong'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)